  ('dietitian-moex-08924', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某甲在工作場所組成一個快樂健走的俱樂部，此種團體可視為下列何種行為改變理論的應用與延伸？', '["Health belief model", "Assure model", "Social support", "Social marketing"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08925', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某種工具除了可評估團體的飲食品質之外，也可以以飲食型態評估慢性疾病的危險性。此種工具稱為：', '["Diet quality index", "Index of nutritional quality", "Healthy eating index", "Estimated average requirement"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08926', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某位營養師進行營養諮詢時，詢問高血壓患者是否計畫在飲食中降低調味料的使用，結果該患者回答： 「我可以試試看，試著從早餐開始。」。請問此種反應代表該患者處於營養教育諮詢理論的「改變階段 模式」（stages of change model）的那一個階段？', '["行動期（action）", "準備期（preparation）", "思考期（contemplation）", "思考前期行為（precontemplation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08927', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某個社區舉辦6-12歲學童的體重控制班，除了發給每位學童護照，並且鼓勵學童家長或監護者陪同上課 和參加課程活動，也在學童護照上貼貼紙註記，以認同家長的參與和提醒家長課後體重控制的注意事項 及技巧，此種營養教育和諮商的方式稱為：', '["全形治療（gestalt therapy）", "行為治療（behavior therapy）", "個人中心治療（person-centered therapy）", "家庭治療（family therapy）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08928', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在國家制訂營養政策的系統模式中，營養教育歸屬於下列那一個階段？', '["Input", "Process", "Outcome", "Structure"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08929', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '在一個「成人體重控制」的計畫要項裡，其中一項是以20萬元是否達成製作身高體重與身體質量指數的 成人轉盤20萬套，分送全國26個地點，此種社區營養計畫評量方法稱為：', '["效果（efforts）", "效率（efficiency）", "效能（effectiveness）", "效益（benefit）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08930', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'SWOT為社區營養計畫擬定執行前的行銷原則分析方法之一，請問“O＂是：', '["Outcomes", "Objectives", "Opportunities", "Operations"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08931', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '1999-2000 臺灣地區老人營養健康狀況調查資料顯示，男女性老人的維生素 B 平均攝取量均大幅低於民 6 國91年行政院衛生署公布的參考攝取量，受到相關學者專家的關注。請問以下敘述，何者對於此次維生 素B 的調查方法和結果相符？ 6', '["此次調查以血漿磷酸吡哆醛濃度做為維生素B 的營養狀況評估 6", "女性平均攝取量顯著高於男性平均攝取量", "維生素B 的膳食攝取量與蛋白質和熱量攝取無關 6", "老人維生素B 缺乏的比例最低的是山地地區 6"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08932', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列有關全球老人與營養問題相關之敘述，何者正確？', '["約有二分之一的老人居住在低收入國家", "女性老人人口與男性老人人口大致相等", "骨質疏鬆造成骨折是老人疾病殘障與死亡主因之一", "男性骨質疏鬆造成骨折危險高於女性，尤其髖關節"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08933', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以下對於1999-2000臺灣地區老人營養健康狀況調查的礦物質攝取結果的敘述，何者錯誤？', '["鈣的攝取量約為105% RDNA，但只達DRIs的63%", "磷、鐵、鎂的攝取量皆已達DRIs參考攝取量", "鈉攝取量大於第一次國民營養健康狀況變遷調查的結果", "鈉的攝取量顯著高於建議量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "c90dd73f29c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
